#include <bits/stdc++.h>
using namespace std;
int main(){
    string name,max_name;int n,cj,bj,lw,maxn=0,all=0,money;char gb,xb;
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>name>>cj>>bj>>gb>>xb>>lw;
        money=0;
        if(cj>80 && lw>=1)money+=8000;
        if(cj>85 && bj>80)money+=4000;
        if(cj>90)money+=2000;
        if(cj>85 && xb=='Y')money+=1000;
        if(bj>80 && gb=='Y')money+=850;
        if(maxn<money){
            maxn=money;
            max_name=name;
        }
        all+=money;
    }
    cout<<max_name<<endl<<maxn<<endl<<all;
    return 0;
}
